   301			return []string{zellijPath, "attach", runtimeTarget}, true
   302		case "tmux":
   303			tmuxPath := p.tmuxPath()
   304			if tmuxPath == "" || !p.hasTmuxSession(ctx, runtimeTarget) {
   305				return nil, false
   306			}
   307	
   308			return tmuxAttachCommand(tmuxPath, runtimeTarget), true
   309		default:
   310			return nil, false
   311		}
