   314	func tmuxAttachCommand(tmuxPath string, target string) []string {
   315		targetArg := "=" + target
   316		shellPath := posixShellPath()
   317		if shellPath == "" {
   318			return []string{tmuxPath, "attach-session", "-t", targetArg}
   319		}
   320	
   321		command := fmt.Sprintf(
   322			"%s capture-pane -e -p -S -%d -t %s 2>/dev/null || true; exec %s attach-session -t %s",
   323			shellQuote(tmuxPath),
   324			tmuxScrollbackCaptureLines,
   325			shellQuote(target),
   326			shellQuote(tmuxPath),
   327			shellQuote(targetArg),
   328		)
   329	
   330		return []string{shellPath, "-lc", command}
   331	}
