   333	func posixShellPath() string {
   334		for _, candidate := range []string{"/bin/sh", "/usr/bin/sh"} {
   335			if _, err := os.Stat(candidate); err == nil {
   336				return candidate
   337			}
   338		}
   339	
   340		if path, err := exec.LookPath("sh"); err == nil {
   341			return path
   342		}
   343	
   344		return ""
   345	}
