import { Terminal, type WTerm } from '@wterm/react';
import { Maximize2Icon, Minimize2Icon, RotateCcwIcon } from 'lucide-react';
import {
  type ReactNode,
  useCallback,
  useEffect,
  useLayoutEffect,
  useRef,
  useState,
} from 'react';
import { toast } from 'sonner';

import { cn } from '@/lib/tailwind/utils';

import { Button } from '@/components/ui/button';
import {
  Tooltip,
  TooltipContent,
  TooltipTrigger,
} from '@/components/ui/tooltip';

import { OpenIdeButton } from '@/features/home/components/molecules/open-ide-button';
import {
  createTerminalWebSocketURL,
  initialTerminalSize,
  isRetryableTerminalStatus,
  type TerminalConnectionStatus,
} from '@/features/home/components/organisms/terminal-connection';
import type { WorkerSession } from '@/features/home/domain/session-workspace';

const textEncoder = new TextEncoder();
const terminalReconnectDelaysMs = [500, 1_000, 2_000] as const;
const terminalResetSequence = '\x1b[3J\x1b[2J\x1b[H';
const terminalStableConnectionMs = 5_000;

type TerminalSize = typeof initialTerminalSize;

export function TerminalPanel(props: {
  className?: string;
  hidden?: boolean;
  session?: WorkerSession;
}) {
  const { session } = props;
  const socketRef = useRef<WebSocket | null>(null);
  const terminalRef = useRef<WTerm | null>(null);
  const terminalPanelRef = useRef<HTMLElement | null>(null);
  const terminalViewportRef = useRef<HTMLDivElement | null>(null);
  const clearBeforeNextMessageRef = useRef(false);
  const reconnectAttemptRef = useRef(0);
  const pendingTerminalResizeFrameRef = useRef<number | undefined>(undefined);
  const pendingTerminalResizeForceRef = useRef(false);
  const terminalSizeRef = useRef(initialTerminalSize);
  const lastConnectionToastRef = useRef<string | undefined>(undefined);
  const [readyTerminalSessionKey, setReadyTerminalSessionKey] = useState<
    string | undefined
  >(undefined);
  const [connectionStatus, setConnectionStatus] =
    useState<TerminalConnectionStatus>('idle');
  const [connectionAttempt, setConnectionAttempt] = useState(0);
  const [isTerminalFullscreen, setIsTerminalFullscreen] = useState(false);

  const sendResize = useCallback((cols: number, rows: number) => {
    const socket = socketRef.current;
    if (!socket || socket.readyState !== WebSocket.OPEN) {
      return;
    }

    socket.send(
      JSON.stringify({
        cols,
        rows,
        type: 'resize',
      })
    );
  }, []);

  const terminalSessionKey = session
    ? `${session.project}/${session.id}`
    : 'idle';
  const sessionId = session?.id;
  const sessionProject = session?.project;
  const sessionTerminalSupported = session?.terminalSupported;
  const sessionWorkerId = session?.workerId;
  const isTerminalReadyForSession =
    readyTerminalSessionKey === terminalSessionKey;

  const applyTerminalSize = useCallback(
    (size: TerminalSize, options?: { forceSend?: boolean }) => {
      const previousSize = terminalSizeRef.current;
      terminalSizeRef.current = size;

      const terminal = terminalRef.current;
      if (
        terminal &&
        isTerminalReadyForSession &&
        (terminal.cols !== size.cols || terminal.rows !== size.rows)
      ) {
        terminal.resize(size.cols, size.rows);
      }

      if (
        options?.forceSend ||
        previousSize.cols !== size.cols ||
        previousSize.rows !== size.rows
      ) {
        sendResize(size.cols, size.rows);
      }
    },
    [isTerminalReadyForSession, sendResize]
  );

  const syncTerminalSize = useCallback(
    (options?: { forceSend?: boolean }) => {
      const terminal = terminalRef.current;
      if (!terminal || !isTerminalReadyForSession) {
        return false;
      }

      const measuredSize = measureTerminalSize(terminal.element);
      if (!measuredSize) {
        return false;
      }

      applyTerminalSize(measuredSize, options);
      return true;
    },
    [applyTerminalSize, isTerminalReadyForSession]
  );

  const scheduleTerminalSizeSync = useCallback(
    (options?: { forceSend?: boolean }) => {
      pendingTerminalResizeForceRef.current =
        pendingTerminalResizeForceRef.current || Boolean(options?.forceSend);

      if (pendingTerminalResizeFrameRef.current !== undefined) {
        return;
      }

      pendingTerminalResizeFrameRef.current = window.requestAnimationFrame(
        () => {
          pendingTerminalResizeFrameRef.current = undefined;
          const forceSend = pendingTerminalResizeForceRef.current;
          pendingTerminalResizeForceRef.current = false;
          syncTerminalSize({ forceSend });
        }
      );
    },
    [syncTerminalSize]
  );

  useEffect(() => {
    const handleFullscreenChange = () => {
      setIsTerminalFullscreen(
        document.fullscreenElement === terminalPanelRef.current
      );

      scheduleTerminalSizeSync({ forceSend: true });
    };

    document.addEventListener('fullscreenchange', handleFullscreenChange);

    return () => {
      document.removeEventListener('fullscreenchange', handleFullscreenChange);
    };
  }, [scheduleTerminalSizeSync]);

  useLayoutEffect(() => {
    const terminal = terminalRef.current;
    if (!terminal || !isTerminalReadyForSession) {
      return;
    }

    const resizeObserver = new ResizeObserver(() => {
      scheduleTerminalSizeSync();
    });
    resizeObserver.observe(terminal.element);

    const terminalViewport = terminalViewportRef.current;
    if (terminalViewport) {
      resizeObserver.observe(terminalViewport);
    }

    const handleViewportResize = () => {
      scheduleTerminalSizeSync();
    };

    window.addEventListener('resize', handleViewportResize);
    window.visualViewport?.addEventListener('resize', handleViewportResize);
    scheduleTerminalSizeSync({ forceSend: true });

    return () => {
      resizeObserver.disconnect();
      window.removeEventListener('resize', handleViewportResize);
      window.visualViewport?.removeEventListener(
        'resize',
        handleViewportResize
      );
    };
  }, [isTerminalReadyForSession, scheduleTerminalSizeSync]);

  useEffect(() => {
    return () => {
      if (pendingTerminalResizeFrameRef.current !== undefined) {
        window.cancelAnimationFrame(pendingTerminalResizeFrameRef.current);
        pendingTerminalResizeFrameRef.current = undefined;
      }
    };
  }, []);

  useEffect(() => {
    clearBeforeNextMessageRef.current = false;
    reconnectAttemptRef.current = 0;
  }, [terminalSessionKey]);

  useEffect(() => {
    const terminal = terminalRef.current;
    if (!sessionId || !sessionProject) {
      setConnectionStatus('idle');
      return;
    }

    if (!sessionTerminalSupported) {
      setConnectionStatus('unsupported');
      return;
    }

    if (!terminal || !isTerminalReadyForSession) {
      setConnectionStatus('connecting');
      return;
    }

    syncTerminalSize();
    const terminalSize = terminalSizeRef.current;
    let active = true;
    let reconnectTimer: number | undefined;
    let stableConnectionTimer: number | undefined;

    const clearReconnectTimer = () => {
      if (reconnectTimer === undefined) {
        return;
      }

      window.clearTimeout(reconnectTimer);
      reconnectTimer = undefined;
    };

    const clearStableConnectionTimer = () => {
      if (stableConnectionTimer === undefined) {
        return;
      }

      window.clearTimeout(stableConnectionTimer);
      stableConnectionTimer = undefined;
    };

    const markTerminalConnectionUseful = () => {
      clearStableConnectionTimer();
      reconnectAttemptRef.current = 0;
    };

    const markTerminalConnectionStableLater = () => {
      clearStableConnectionTimer();
      stableConnectionTimer = window.setTimeout(() => {
        stableConnectionTimer = undefined;
        reconnectAttemptRef.current = 0;
      }, terminalStableConnectionMs);
    };

    const scheduleTerminalReconnect = () => {
      if (reconnectTimer !== undefined) {
        return;
      }

      const nextDelay = terminalReconnectDelaysMs[reconnectAttemptRef.current];
      if (nextDelay === undefined) {
        return;
      }

      reconnectAttemptRef.current += 1;
      reconnectTimer = window.setTimeout(() => {
        reconnectTimer = undefined;
        clearBeforeNextMessageRef.current = true;
        setConnectionAttempt((currentAttempt) => currentAttempt + 1);
      }, nextDelay);
    };

    const socket = new WebSocket(
      createTerminalWebSocketURL(
        { id: sessionId, project: sessionProject },
        window.location,
        terminalSize
      )
    );
    socket.binaryType = 'arraybuffer';
    socketRef.current = socket;
    setConnectionStatus('connecting');

    socket.addEventListener('open', () => {
      if (!active) {
        return;
      }

      clearReconnectTimer();
      markTerminalConnectionStableLater();
      setConnectionStatus('connected');
      syncTerminalSize({ forceSend: true });
    });

    socket.addEventListener('message', (event) => {
      if (!active) {
        return;
      }

      markTerminalConnectionUseful();
      const currentTerminal = terminalRef.current;
      if (!currentTerminal) {
        return;
      }

      if (clearBeforeNextMessageRef.current) {
        currentTerminal.write(terminalResetSequence);
        clearBeforeNextMessageRef.current = false;
      }
      writeTerminalMessage(currentTerminal, event.data);
    });

    socket.addEventListener('error', () => {
      if (active) {
        clearStableConnectionTimer();
        setConnectionStatus('failed');
        scheduleTerminalReconnect();
      }
    });

    socket.addEventListener('close', (event) => {
      if (!active) {
        return;
      }

      if (event.wasClean) {
        clearStableConnectionTimer();
        setConnectionStatus('disconnected');
        return;
      }

      clearStableConnectionTimer();
      setConnectionStatus('failed');
      scheduleTerminalReconnect();
    });

    return () => {
      active = false;
      if (socketRef.current === socket) {
        socketRef.current = null;
      }

      clearStableConnectionTimer();
      clearReconnectTimer();
      socket.close(1000, 'terminal session changed');
    };
  }, [
    connectionAttempt,
    isTerminalReadyForSession,
    sessionId,
    sessionProject,
    sessionTerminalSupported,
    syncTerminalSize,
  ]);

  const handleTerminalReady = useCallback(
    (terminal: WTerm) => {
      terminalRef.current = terminal;

      if (isTerminalReadyForSession) {
        scheduleTerminalSizeSync({ forceSend: true });
        return;
      }

      const measuredSize = measureTerminalSize(terminal.element);
      if (measuredSize) {
        terminalSizeRef.current = measuredSize;
        if (
          terminal.cols !== measuredSize.cols ||
          terminal.rows !== measuredSize.rows
        ) {
          terminal.resize(measuredSize.cols, measuredSize.rows);
        }
      }
      setReadyTerminalSessionKey(terminalSessionKey);
    },
    [isTerminalReadyForSession, scheduleTerminalSizeSync, terminalSessionKey]
  );

  const handleTerminalData = useCallback((data: string) => {
    const socket = socketRef.current;
    if (!socket || socket.readyState !== WebSocket.OPEN) {
      return;
    }

    socket.send(textEncoder.encode(data));
  }, []);

  const handleTerminalResize = useCallback(
    (cols: number, rows: number) => {
      applyTerminalSize({ cols, rows });
    },
    [applyTerminalSize]
  );

  const handleTerminalError = useCallback((error: unknown) => {
    console.error('wterm failed to initialize', error);
    setConnectionStatus('failed');
  }, []);

  const handleTerminalRetry = useCallback(() => {
    clearBeforeNextMessageRef.current = true;
    reconnectAttemptRef.current = 0;
    setConnectionAttempt((currentAttempt) => currentAttempt + 1);
  }, []);

  useEffect(() => {
    if (!sessionId || !sessionWorkerId) {
      lastConnectionToastRef.current = undefined;
      return;
    }

    const toastKey = `${sessionId}:${connectionAttempt}:${connectionStatus}`;
    if (lastConnectionToastRef.current === toastKey) {
      return;
    }

    switch (connectionStatus) {
      case 'unsupported':
        toast.warning('Terminal unavailable', {
          description: `${sessionWorkerId} does not expose an attachable runtime.`,
        });
        lastConnectionToastRef.current = toastKey;
        return;
      case 'disconnected':
        toast.warning('Terminal disconnected', {
          action: {
            label: 'Reconnect',
            onClick: handleTerminalRetry,
          },
          description: `${sessionWorkerId} stopped streaming terminal output.`,
        });
        lastConnectionToastRef.current = toastKey;
        return;
      case 'failed':
        toast.error('Terminal connection failed', {
          action: {
            label: 'Reconnect',
            onClick: handleTerminalRetry,
          },
          description: `${sessionWorkerId} could not attach to the worker runtime.`,
        });
        lastConnectionToastRef.current = toastKey;
        return;
      default:
        return;
    }
  }, [
    connectionAttempt,
    connectionStatus,
    handleTerminalRetry,
    sessionId,
    sessionWorkerId,
  ]);

  const handleTerminalFullscreenToggle = useCallback(() => {
    const terminalPanel = terminalPanelRef.current;

    if (!terminalPanel) {
      return;
    }

    if (document.fullscreenElement === terminalPanel) {
      void document.exitFullscreen();
      return;
    }

    void terminalPanel.requestFullscreen();
  }, []);

  const terminalLabel = session
    ? session.kind === 'orchestrator'
      ? 'Orchestrator terminal'
      : `${session.workerId} terminal`
    : 'Worker terminal';
  const fullscreenButtonLabel = isTerminalFullscreen
    ? 'Restore terminal'
    : 'Maximize terminal';
  const canRetry = isRetryableTerminalStatus(connectionStatus);

  return (
    <section
      ref={terminalPanelRef}
      aria-label={`${terminalLabel} panel`}
      aria-hidden={props.hidden ? true : undefined}
      data-acceptance-anchor="terminal-panel"
      hidden={props.hidden}
      className={cn(
        'relative flex min-h-90 min-w-0 flex-1 flex-col border-b border-border bg-background md:min-h-0 md:border-b-0',
        isTerminalFullscreen && 'h-dvh w-dvw border-b-0',
        props.className
      )}
    >
      <div
        ref={terminalViewportRef}
        className={cn(
          'min-h-0 flex-1 bg-background p-3',
          isTerminalFullscreen && 'p-0'
        )}
      >
        <Terminal
          key={terminalSessionKey}
          aria-label={terminalLabel}
          autoResize
          className="ao-terminal"
          cols={initialTerminalSize.cols}
          cursorBlink
          onData={handleTerminalData}
          onError={handleTerminalError}
          onReady={handleTerminalReady}
          onResize={handleTerminalResize}
          rows={initialTerminalSize.rows}
          wasmUrl="/wterm.wasm"
        />
      </div>

      <div className="absolute top-3 right-3 flex items-center">
        {canRetry ? (
          <IconButton label="Reconnect terminal" onClick={handleTerminalRetry}>
            <RotateCcwIcon />
          </IconButton>
        ) : null}
        <OpenIdeButton session={session} />
        <IconButton
          label={fullscreenButtonLabel}
          onClick={handleTerminalFullscreenToggle}
        >
          {isTerminalFullscreen ? <Minimize2Icon /> : <Maximize2Icon />}
        </IconButton>
      </div>
    </section>
  );
}

function measureTerminalSize(element: HTMLElement): TerminalSize | undefined {
  const rect = element.getBoundingClientRect();
  if (rect.width <= 0 || rect.height <= 0) {
    return undefined;
  }

  const row = document.createElement('div');
  row.className = 'term-row';
  row.style.position = 'absolute';
  row.style.visibility = 'hidden';
  row.style.pointerEvents = 'none';
  row.style.whiteSpace = 'pre';
  row.style.top = '0';
  row.style.left = '0';

  const probe = document.createElement('span');
  probe.textContent = 'W';
  row.appendChild(probe);
  element.appendChild(row);

  const charWidth = probe.getBoundingClientRect().width;
  const rowHeight = row.getBoundingClientRect().height;
  row.remove();

  if (charWidth <= 0 || rowHeight <= 0) {
    return undefined;
  }

  const style = getComputedStyle(element);
  const paddingX =
    toPixelNumber(style.paddingLeft) + toPixelNumber(style.paddingRight);
  const paddingY =
    toPixelNumber(style.paddingTop) + toPixelNumber(style.paddingBottom);
  const availableWidth = element.clientWidth - paddingX;
  const availableHeight = element.clientHeight - paddingY;

  if (availableWidth <= 0 || availableHeight <= 0) {
    return undefined;
  }

  return {
    cols: Math.max(1, Math.floor(availableWidth / charWidth)),
    rows: Math.max(1, Math.floor(availableHeight / rowHeight)),
  };
}

function toPixelNumber(value: string) {
  const parsed = Number.parseFloat(value);
  return Number.isFinite(parsed) ? parsed : 0;
}

function IconButton(props: {
  label: string;
  children: ReactNode;
  onClick?: () => void;
}) {
  return (
    <Tooltip>
      <TooltipTrigger
        render={
          <Button
            type="button"
            variant="secondary"
            size="icon"
            className="size-9 rounded-none shadow-none"
            aria-label={props.label}
            onClick={props.onClick}
          />
        }
      >
        {props.children}
      </TooltipTrigger>
      <TooltipContent>
        <p>{props.label}</p>
      </TooltipContent>
    </Tooltip>
  );
}

function writeTerminalMessage(terminal: WTerm, data: unknown) {
  if (typeof data === 'string') {
    terminal.write(data);
    return;
  }

  if (data instanceof ArrayBuffer) {
    terminal.write(new Uint8Array(data));
    return;
  }

  if (data instanceof Blob) {
    void data.arrayBuffer().then((buffer) => {
      terminal.write(new Uint8Array(buffer));
    });
  }
}

